
'use client';
import React, { useState, useEffect } from 'react';
import { FileText, CheckCircle, XCircle } from 'lucide-react';
import { getLibraryBorrowingsAction } from '@/app/actions/dbActions';
import { LibraryBorrowing } from '@/utils/storage';

export default function BorrowRequests() {
  const [requests, setRequests] = useState<LibraryBorrowing[]>([]);

  useEffect(() => {
    loadRequests();
  }, []);

  const loadRequests = async () => {
    const allRequests = await getLibraryBorrowingsAction();
    // This component should show pending requests, but the model does not support it yet.
    // Showing all for now.
    setRequests(allRequests.sort((a, b) => new Date(b.borrowDate).getTime() - new Date(a.borrowDate).getTime()));
  };

  const handleApprove = (requestId: string) => {
    alert(`Approve functionality for ${requestId} not implemented.`);
  };

  const handleDecline = (requestId: string) => {
    alert(`Decline functionality for ${requestId} not implemented.`);
  };

  return (
    <div>
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-3xl mb-2">Borrow Requests</h2>
          <p className="text-gray-600">Review and process borrow requests</p>
        </div>
      </div>

      <div className="space-y-4">
        {requests.length === 0 ? (
          <div className="bg-white rounded-xl shadow-lg p-12 text-center">
            <FileText size={64} className="mx-auto mb-4 text-gray-300" />
            <p className="text-gray-500 text-lg">No borrow requests</p>
          </div>
        ) : (
          requests.map((request) => (
            <div key={request.id} className="bg-white rounded-xl shadow-lg p-6">
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <h3 className="text-xl mb-2">{request.bookId}</h3>
                  <p className="text-gray-600 mb-1">
                    Student: {request.studentId}
                  </p>
                  <p className="text-sm text-gray-500">
                    Requested: {new Date(request.borrowDate).toLocaleString()}
                  </p>
                  {request.dueDate && (
                    <p className="text-sm text-gray-600 mt-2">
                      Due: {new Date(request.dueDate).toLocaleDateString()}
                    </p>
                  )}
                </div>
                <div className="flex flex-col gap-2">
                  <span className={`px-4 py-2 rounded-full text-sm ${
                    request.status === 'borrowed' ? 'bg-yellow-100 text-yellow-800' :
                    'bg-green-100 text-green-800'
                  }`}>
                    {request.status}
                  </span>
                  {request.status === 'borrowed' && ( // Assuming 'borrowed' means pending admin approval in this context
                    <>
                      <button
                        onClick={() => handleApprove(request.id)}
                        className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 flex items-center gap-2"
                      >
                        <CheckCircle size={18} />
                        Approve
                      </button>
                      <button
                        onClick={() => handleDecline(request.id)}
                        className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 flex items-center gap-2"
                      >
                        <XCircle size={18} />
                        Decline
                      </button>
                    </>
                  )}
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}
